// Limpia formato Markdown problemático antes de enviar a Telegram
const datos = $input.first().json;

let textoOriginal = datos.output || datos.text || '';

let textoLimpio = textoOriginal
  // Quitar doble asterisco
  .replace(/\*\*(.*?)\*\*/g, '$1')
  // Quitar asterisco simple
  .replace(/\*(.*?)\*/g, '$1')
  // Quitar guion bajo Markdown (cursiva) — pero NO los que están dentro de palabras
  .replace(/(?<=\s|^)_([^_\n]+?)_(?=\s|$|[.,!?:])/g, '$1')
  // Quitar headers Markdown
  .replace(/^#{1,6}\s+/gm, '')
  // Quitar líneas separadoras
  .replace(/^[\-=]{3,}$/gm, '')
  // Quitar acentos graves
  .replace(/`([^`]+)`/g, '$1')
  // Quitar bloques de código
  .replace(/```[\s\S]*?```/g, '')
  // Convertir \n literal a salto de línea real
  .replace(/\\n/g, '\n')
  // Limpiar múltiples saltos de línea
  .replace(/\n{3,}/g, '\n\n');

// Escapar caracteres especiales de Markdown Legacy que pueden romper Telegram
// En Markdown Legacy estos caracteres tienen significado: _ * [ ` 
// Los escapamos para que se vean literales
textoLimpio = textoLimpio
  // Escapar guiones bajos dentro de palabras (id_estudiante → id\_estudiante)
  .replace(/_/g, '\\_')
  // Escapar asteriscos sueltos restantes
  .replace(/\*/g, '\\*')
  // Escapar corchetes (no muy comunes pero por si acaso)
  .replace(/\[/g, '\\[')
  .replace(/\]/g, '\\]');

return [{ json: { output: textoLimpio } }];

